import json, subprocess, sys, os
from email.utils import parsedate_to_datetime
from datetime import timezone, timedelta

GAPI = "/root/.hermes/skills/productivity/google-workspace/scripts/google_api.py"
ENV = {**os.environ, "PATH": "/usr/bin:/bin:/root/.local/bin", "HERMES_GWS_BIN": "/root/.local/bin/gws", "HOME": "/root", "HERMES_HOME": "/root/.hermes"}
TZ_VN = timezone(timedelta(hours=7))


def run(args):
    p = subprocess.run([sys.executable, GAPI] + args, capture_output=True, text=True, env=ENV)
    if p.returncode != 0:
        raise SystemExit(p.stderr or p.stdout)
    return json.loads(p.stdout)


def clean_body(text, max_len=700):
    if not text:
        return ""
    lines = []
    for line in text.splitlines():
        line = line.strip()
        if not line:
            continue
        low = line.lower()
        if any(marker in low for marker in [
            "unsubscribe", "click here", "view in browser", "privacy policy",
            "©", "copyright", "all rights reserved", "sent from my", "get outlook",
            "________________________________", "---", "___",
            "https://", "http://", "www.",
        ]):
            continue
        lines.append(line)
    text = "\n".join(lines)
    return (text[:max_len] + "...") if len(text) > max_len else text


def fmt_date(s):
    try:
        return parsedate_to_datetime(s).astimezone(TZ_VN).strftime('%d/%m %H:%M')
    except Exception:
        return s

for qname, query in [("inbox", "in:inbox after:2026/04/21 before:2026/04/24"), ("sent", "in:sent after:2026/04/21 before:2026/04/24")]:
    msgs = run(["gmail", "search", query, "--max", "50"])
    out = []
    for m in msgs:
        full = run(["gmail", "get", m["id"]])
        out.append({
            "id": m.get("id"),
            "subject": full.get("subject") or m.get("subject"),
            "from": full.get("from") or m.get("from"),
            "to": full.get("to") or m.get("to"),
            "date": fmt_date(full.get("date") or m.get("date", "")),
            "snippet": m.get("snippet", ""),
            "body": clean_body(full.get("body", "") or m.get("snippet", "")),
        })
    print(f'## {qname.upper()} ({len(out)})')
    print(json.dumps(out, ensure_ascii=False, indent=2))
